mapper.select:
/* selectWalsmaList */ SELECT ALSTRMD AS ROWKEY, ALSTRMD, ALSTRNM, ALSTRTG, ALSTROD, ALUSEYN, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK FROM ${userInfo.schema}.WALSMA
AND ALSTRMD LIKE UPPER(CONCAT('%', #{param.alstrmd}, '%'))
AND ALSTRNM LIKE UPPER(CONCAT('%', #{param.alstrnm}, '%'))
AND ALUSEYN = #{param.aluseyn}
ORDER BY ALSTROD ASC

/* selectWalshdList */ SELECT CONCAT(HD.WAREKEY, HD.ALSTRKY) AS ROWKEY, HD.WAREKEY, HD.ALSTRKY, WA.WHNAMLC, HD.ALSTRNM, HD.ALUSEYN, HD.CREDATE, HD.CRETIME, HD.CREUSER, HD.LMODATE, HD.LMOTIME, HD.LMOUSER, HD.UPDTCHK FROM ${userInfo.schema}.WALSHD HD INNER JOIN ${userInfo.schema}.MWARMA WA ON( HD.WAREKEY = WA.WAREKEY )
AND HD.WAREKEY = #{param.warekey}
AND HD.ALSTRKY LIKE UPPER(CONCAT('%', #{param.alstrky}, '%'))
AND HD.ALSTRNM LIKE UPPER(CONCAT('%', #{param.alstrnm}, '%'))
AND HD.ALUSEYN = #{param.aluseyn}
ORDER BY HD.WAREKEY, HD.ALSTRKY

/* selectWalsitList */
SELECT
	CONCAT(IT.WAREKEY, IT.ALSTRKY, IT.ALSTRIT) AS ROWKEY,
	IT.WAREKEY, IT.ALSTRKY, IT.ALSTRIT,
	IT.ALSTRMD, IT.ALSTRWG, IT.ALSTRST, IT.ALESTYN, IT.ALUSEYN,
	WA.WHNAMLC, AM.ALSTRNM, AM.ALSTRTG,
	IT.CREDATE, IT.CRETIME, IT.CREUSER, IT.LMODATE, IT.LMOTIME,
	IT.LMOUSER, IT.UPDTCHK
FROM
	${userInfo.schema}.WALSIT IT
	INNER JOIN ${userInfo.schema}.MWARMA WA ON(
		IT.WAREKEY = WA.WAREKEY
	)
	INNER JOIN ${userInfo.schema}.WALSHD HD ON(
		IT.WAREKEY = HD.WAREKEY AND IT.ALSTRKY = HD.ALSTRKY
	)
	INNER JOIN ${userInfo.schema}.WALSMA AM ON(
		IT.ALSTRMD = AM.ALSTRMD
	)


	AND IT.WAREKEY = #{param.warekey}


	AND IT.ALSTRKY = #{param.alstrky}


	AND IT.ALUSEYN = #{param.aluseyn}


ORDER BY IT.ALSTRKY, IT.ALSTRIT

/* selectWalordList */
SELECT
	CONCAT(OD.WAREKEY, OD.DOCCATE, OD.DOCTYPE) AS ROWKEY,
	OD.WAREKEY, OD.DOCCATE, OD.DOCTYPE,
	WA.WHNAMLC, DO.DOCCTNM, DO.DOCTYNM, OD.ALSTRKY,
	OD.ALUSEYN,
	OD.CREDATE, OD.CRETIME, OD.CREUSER, OD.LMODATE, OD.LMOTIME,
	OD.LMOUSER, OD.UPDTCHK
FROM
	${userInfo.schema}.WALORD OD
	INNER JOIN ${userInfo.schema}.MWARMA WA ON(
		OD.WAREKEY = WA.WAREKEY
	)
	INNER JOIN ${userInfo.schema}.MDOCMA DO ON(
		DO.WAREKEY = WA.WAREKEY AND OD.DOCCATE = DO.DOCCATE AND OD.DOCTYPE = DO.DOCTYPE
	)
	INNER JOIN ${userInfo.schema}.WALSHD HD ON(
		OD.WAREKEY = HD.WAREKEY AND OD.ALSTRKY = HD.ALSTRKY
	)


	AND OD.WAREKEY = #{param.warekey}


	AND OD.ALSTRKY like UPPER(CONCAT('%', #{param.alstrky}, '%'))


	AND OD.DOCCATE = #{param.doccate}


	AND OD.DOCTYPE = #{param.doctype}


	AND OD.ALUSEYN = #{param.aluseyn}


ORDER BY OD.WAREKEY, OD.DOCCATE, OD.DOCTYPE

/* selectWalordWithWalsit */ SELECT
WAI.WAREKEY, WAI.ALSTRKY, WAI.ALSTRIT,
WAI.ALSTRMD, WAI.ALSTRST, WAI.ALSTRWG,
WAM.ALSTRNM AS ALSTRNM,
WAH.ALSTRNM AS ALSTHNM,
WAO.DOCCATE, WAO.DOCTYPE FROM ${userInfo.schema}.WALSIT WAI INNER JOIN ${userInfo.schema}.WALSHD WAH ON WAH.ALSTRKY = WAI.ALSTRKY AND WAH.WAREKEY = WAI.WAREKEY INNER JOIN ${userInfo.schema}.WALSMA WAM ON WAM.ALSTRMD = WAI.ALSTRMD INNER JOIN ${userInfo.schema}.WALORD WAO ON WAO.ALSTRKY = WAI.ALSTRKY AND WAO.WAREKEY = WAI.WAREKEY WHERE WAI.ALUSEYN = 'Y' AND WAH.ALUSEYN = 'Y' AND WAM.ALUSEYN = 'Y' AND WAO.ALUSEYN = 'Y' AND WAI.WAREKEY = #{param.warekey} AND WAO.DOCCATE = #{param.doccate} AND WAO.DOCTYPE = #{param.doctype}

/* selectStockListForAllocationStrategy */ SELECT
WST.STOCKKY,
WST.WAREKEY, WST.AREAKEY, WST.LOCAKEY, WST.LOLAYER, WST.SAVEPNT, WST.LOTNMKY, WST.OWNERKY, WST.OWNRNAM, WST.CUSTCOD, WST.CUSTNAM, WST.FNCUSKY, WST.FCNAMLC, WST.SKUGRKY, WST.SKUMKEY, WST.SKUDESC, WST.SKUWEIG, WST.SKUWIDT, WST.SKULENG, WST.SKUTHIC, WST.STLOTNB, WST.GROSSWG, WST.GROSSLN, WST.GROSSWD, WST.GROSSTH, WST.BTRCATE, WST.BTRFSTC, WST.PURCNUM, WST.ORDERLN, WST.REGIKEY, WST.DESTKEY, WST.REGIORG, WST.REGIMOD, WST.DESTORG, WST.DEORGNM, WST.DESTMOD, WST.ITEMCOD, WST.DEMODNM, WST.DEMODYN, WST.DEMDMAN, WST.DEMPOCD, WST.DEMDADR, WST.DEMDTLN, WST.STOTQTY, WST.SALLQTY, WST.SBLOQTY, WST.SUOMKEY, WST.ADDCOKY, WST.POSHPDT, WST.POSHPTM, WST.POSHPDY, WST.SHPLIMT, WST.DELVDSR, WST.STKMEMO, WST.EMSKUYN, WST.RCVDCDT, WST.LOTAT01, WST.LOTAT02, WST.LOTAT03, WST.STKSTAT, WST.BLOCKID, WST.RCVDCKY, WST.RCVDCIT, WST.ADJSOKY, WST.ADJSOIT, WST.PHYSOKY, WST.PHYSOIT, WST.SHPDCKY, WST.SHPDCIT, WST.TASKOKY, WST.TASKOIT,
MR1.RENAMLC AS REORGNM, MR2.RENAMLC AS REMODNM, MW.WHNAMLC AS WHNAMLC, MA.AREANAM AS AREANAM, MLO.LOCANAM AS LOCANAM, MCO1.COMCDTX AS STKSTNM, MC02.COMCDTX AS ADDCONM, MP.GRPKYNM,
DATE_FORMAT(WST.CREDATE, '%Y-%m-%d') AS CREDATE, DATE_FORMAT(STR_TO_DATE(WST.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME, ${userInfo.schema}.FN_SY_USERNAM(WST.CREUSER) AS CREUSER, DATE_FORMAT(WST.LMODATE, '%Y-%m-%d') AS LMODATE, DATE_FORMAT(STR_TO_DATE(WST.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME, ${userInfo.schema}.FN_SY_USERNAM(WST.LMOUSER) AS LMOUSER, WST.UPDTCHK, ( MLO.OUBOPRI
+ IF(WST.OWNERKY = #{order.ownerky}, #{strategy.alstrwg} , 0)
+ IF(WST.REGIMOD = #{order.regikey}, #{strategy.alstrwg} , 0)
+ IF(WST.DESTMOD = #{order.destkey}, #{strategy.alstrwg} , 0)
+ IF(WST.SKUGRKY = #{order.skugrky}, #{strategy.alstrwg} , 0)
+ IF((SELECT COUNT(OBI.FRLOCKY) FROM ${userInfo.schema}.OOUBIT OBI WHERE OBI.FRLOCKY IN(WST.LOCAKEY)) > 0, 100 + WST.LOLAYER , (WST.LOLAYER / 2)) ) AS PRIORITY_SCORE FROM ${userInfo.schema}.WSTKKY WST INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = WST.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MAREMA MA ON MA.WAREKEY = WST.WAREKEY AND MA.AREAKEY = WST.AREAKEY AND MA.ARUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MLOCMA MLO ON WST.WAREKEY = MLO.WAREKEY AND WST.AREAKEY = MLO.AREAKEY AND WST.LOCAKEY = MLO.LOCAKEY AND MLO.LOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.OOUBHD OBH ON WST.WAREKEY = OBH.WAREKEY LEFT JOIN ${userInfo.schema}.OOUBIT OBI ON OBH.WAREKEY = OBI.WAREKEY AND OBH.OUTBOKY = OBI.OUTBOKY INNER JOIN ${userInfo.schema}.MCODEM MCO1 ON MCO1.COMCDVL = WST.STKSTAT AND MCO1.COMCDKY = 'STKSTAT' AND MCO1.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MREGMA MR1 ON MR1.REGIKEY = WST.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MREGMA MR2 ON MR2.REGIKEY = WST.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = WST.ADDCOKY INNER JOIN ${userInfo.schema}.MCODEM MC02 ON BA.ADDSIKY = MC02.COMCDVL AND MC02.COMCDKY = 'ADDSIKY' AND MC02.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MGRPMA MP ON MP.SKUGRKY = WST.SKUGRKY WHERE WST.WAREKEY = #{order.warekey} AND WST.STOTQTY > 0 AND WST.SALLQTY = 0 AND WST.SBLOQTY = 0 AND WST.PLANQTY = 0 AND WST.PLCMQTY = 0 AND WST.TASKQTY = 0 AND MLO.LOCSTAT = 'NORMAL' AND MLO.LOCTYPE = 'BED' AND OBH.OUTBOKY = #{order.outboky}
AND WST.REGIMOD = #{order.regikey}
AND WST.DESTMOD = #{order.destkey}
AND WST.OWNERKY = #{order.ownerky}
AND WST.DEMODNM = UPPER(TRIM(#{order.denamlc}))
AND WST.DEMDADR LIKE CONCAT('%', UPPER(TRIM(#{order.desaddr})), '%')
AND WST.SKUGRKY = #{order.skugrky}
GROUP BY
WST.STOCKKY,
WST.WAREKEY, WST.AREAKEY, WST.LOCAKEY, WST.LOLAYER, WST.SAVEPNT, WST.LOTNMKY, WST.OWNERKY, WST.OWNRNAM, WST.CUSTCOD, WST.CUSTNAM, WST.FNCUSKY, WST.FCNAMLC, WST.SKUGRKY, WST.SKUMKEY, WST.SKUDESC, WST.SKUWEIG, WST.SKUWIDT, WST.SKULENG, WST.SKUTHIC, WST.STLOTNB, WST.GROSSWG, WST.GROSSLN, WST.GROSSWD, WST.GROSSTH, WST.BTRCATE, WST.BTRFSTC, WST.PURCNUM, WST.ORDERLN, WST.REGIKEY, WST.DESTKEY, WST.REGIORG, WST.REGIMOD, WST.DESTORG, WST.DEORGNM, WST.DESTMOD, WST.ITEMCOD, WST.DEMODNM, WST.DEMODYN, WST.DEMDMAN, WST.DEMPOCD, WST.DEMDADR, WST.DEMDTLN, WST.STOTQTY, WST.SALLQTY, WST.SBLOQTY, WST.SUOMKEY, WST.ADDCOKY, WST.POSHPDT, WST.POSHPTM, WST.POSHPDY, WST.SHPLIMT, WST.DELVDSR, WST.STKMEMO, WST.EMSKUYN, WST.RCVDCDT, WST.LOTAT01, WST.LOTAT02, WST.LOTAT03, WST.STKSTAT, WST.BLOCKID, WST.RCVDCKY, WST.RCVDCIT, WST.ADJSOKY, WST.ADJSOIT, WST.PHYSOKY, WST.PHYSOIT, WST.SHPDCKY, WST.SHPDCIT, WST.TASKOKY, WST.TASKOIT, MR1.RENAMLC, MR2.RENAMLC, MW.WHNAMLC, MA.AREANAM, MLO.LOCANAM, MCO1.COMCDTX, MC02.COMCDTX, MP.GRPKYNM,
WST.CREDATE, WST.CRETIME, WST.CREUSER, WST.LMODATE, WST.LMOTIME, WST.LMOUSER, WST.UPDTCHK ORDER BY PRIORITY_SCORE DESC, WST.WAREKEY, WST.AREAKEY, WST.LOCAKEY, WST.LOLAYER DESC
